      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'urgent_indicator',
          role: 'DISAMBIGUATOR',
          bonus_applied: 5,
        })
      );
    });

    test('should enforce DISAMBIGUATOR caps at 10 points', async () => {
      // Add multiple DISAMBIGUATOR attributes
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.7,
        evidence: 'Urgent keywords found',
