      mockConfig.processing_config.attribute_relevance.PERSONAL.category_roles.business_language = 'FILTER';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const filterInfluences = result.influence_applications.filter(
        (app) => app.category === 'PERSONAL' && app.role === 'FILTER'
      );

      const totalFilterPenalty = filterInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalFilterPenalty).toBeGreaterThanOrEqual(-40); // More negative than -40 not allowed
    });
  });

  describe('Subtype Role Processing', () => {
    test('should apply subtype-specific role bonuses', async () => {
      // BILLING subtype has invoice_pattern as CORE
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.9,
        evidence: 'Invoice pattern detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should apply subtype-specific bonus for FINANCIAL.BILLING
      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          subtype: 'BILLING',
          attribute: 'invoice_pattern',
          role: 'CORE',
          bonus_applied: 25,
        })
      );
    });

    test('should handle category vs subtype role conflicts', async () => {
      // end_of_month is SECONDARY_BOOST for category but PRIMARY_BOOST for BILLING subtype
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.7,
        evidence: 'End of month timing',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Subtype role should take precedence
      const subtypeInfluence = result.influence_applications.find(
        (app) => app.category === 'FINANCIAL' && app.subtype === 'BILLING' && app.attribute === 'end_of_month'
      );

      expect(subtypeInfluence).toEqual(
        expect.objectContaining({
          role: 'PRIMARY_BOOST', // Subtype role takes precedence
          bonus_applied: 15, // PRIMARY_BOOST bonus
        })
      );
    });
  });

  describe('Performance and Processing Metadata', () => {
    test('should track processing duration', async () => {
      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.processing_duration_ms).toBeGreaterThan(0);
      expect(result.processing_duration_ms).toBeLessThan(1000); // Should be fast
    });

    test('should track configuration references', async () => {
      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.configuration_references).toEqual(
        expect.objectContaining({
          attribute_relevance_path: 'processing_config.attribute_relevance',
          bonus_config_path: 'processing_config.attribute_bonus_config',
        })
      );
    });

    test('should preserve existing context data', async () => {
      const originalContext = { ...mockContext };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Original context should be preserved
      expect(mockContext.emailId).toBe(originalContext.emailId);
      expect(mockContext.detectionMetadata).toEqual(originalContext.detectionMetadata);
    });
  });

  describe('Error Handling and Edge Cases', () => {
    test('should handle missing attribute relevance configuration', async () => {
      // Remove attribute relevance configuration
      delete mockConfig.processing_config.attribute_relevance;

      await expect(executeAttributeInfluence(mockEmail, mockContext, mockConfig)).rejects.toThrow(
        'Attribute relevance configuration not found'
      );
    });

    test('should handle unknown attributes gracefully', async () => {
      // Add unknown attribute to context
      mockContext.detectionMetadata.unknown_attribute = {
        detectedAt: new Date(),
        detectionMethod: 'unknown',
        confidence: 0.5,
        evidence: 'Unknown attribute',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should not crash, unknown attributes ignored
      expect(result.influence_applications).not.toContainEqual(
        expect.objectContaining({
          attribute: 'unknown_attribute',
        })
      );
    });

    test('should handle empty detection metadata', async () => {
      mockContext.detectionMetadata = {};

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toHaveLength(0);
      expect(result.processing_duration_ms).toBeGreaterThan(0);
    });

    test('should validate role configurations', async () => {
      // Invalid role in configuration
      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.financial_domain =
        'INVALID_ROLE' as any;

      await expect(executeAttributeInfluence(mockEmail, mockContext, mockConfig)).rejects.toThrow(
        'Invalid attribute role: INVALID_ROLE'
      );
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should work with attribute detection results', async () => {
      // Simulate typical attribute detection output
      mockContext.detectionMetadata = {
        financial_domain: {
          detectedAt: new Date(),
          detectionMethod: 'domain_lookup',
          confidence: 0.95,
          evidence: 'Domain: financial.com',
        },
        invoice_pattern: {
          detectedAt: new Date(),
          detectionMethod: 'regex_pattern',
          confidence: 0.88,
          evidence: 'Invoice number pattern found',
        },
        end_of_month: {
          detectedAt: new Date(),
          detectionMethod: 'temporal_analysis',
          confidence: 0.72,
          evidence: 'Email sent on last day of month',
        },
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should process all detected attributes with appropriate roles
      expect(result.influence_applications).toHaveLength(6); // 3 attributes × 2 categories

      const financialInfluences = result.influence_applications.filter((app) => app.category === 'FINANCIAL');
      expect(financialInfluences).toHaveLength(3);
    });

    test('should preserve stage chain data', async () => {
      // Simulate data from previous stages
      const emailWithStageData = {
        ...mockEmail,
        stage_results: {
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
        },
      } as any;

      const result = await executeAttributeInfluence(emailWithStageData, mockContext, mockConfig);

      // Should preserve previous stage data
      expect(result.stage_results).toEqual(
        expect.objectContaining({
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
          attribute_influence: { completed: true },
        })
      );
    });
  });
});

