/**
 * Unit tests for T033: Disambiguation Stage
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests validate:
 * - Pairwise category conflicts and resolution
 * - Confidence gap thresholds
 * - Score adjustment scenarios
 * - Configuration validation
 */

import { describe, test, expect, beforeEach } from '@jest/globals';
import { EmailMessage } from '../../src/types/email-message';
import { AttributeContext } from '../../src/types/attribute-context';
import { CategoryConfiguration } from '../../src/types/category-configuration';
import { executeDisambiguation } from '../../src/stages/disambiguation';

describe('Disambiguation Stage (T033)', () => {
  let mockEmail: EmailMessage;
  let mockContext: AttributeContext;
  let mockConfig: CategoryConfiguration;

  beforeEach(() => {
    // Setup test email
    mockEmail = {
      id: 'test-email-123',
      threadId: 'thread-456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'test@example.com' },
          { name: 'Subject', value: 'Test Email' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' },
      },
      bodyPlain: 'Test email body',
      bodyHtml: '<p>Test email body</p>',
      subject: 'Test Email',
      from: 'test@example.com',
      to: ['recipient@example.com'],
      date: new Date('2024-01-01T10:00:00Z'),
      snippet: 'Test email body',
    } as EmailMessage;

    // Setup attribute context
    mockContext = {
      emailId: 'test-email-123',
      urgency: 'medium',
      domains: ['financial.com'],
      structuralPatterns: ['invoice_pattern'],
      temporalSignals: ['end_of_month'],
      detectionMetadata: {},
      influenceApplications: [],
      derivedAttributes: {},
      attributeRelationships: [],
    };

    // Setup category configuration with disambiguation settings
    mockConfig = {
      version: '1.0',
      updated: '2024-01-01',
      top_level_categories: {
        FINANCIAL: {
          subtypes: {
            BILLING: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
            INSURANCE: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
          },
        },
        PERSONAL: {
          subtypes: {
            FAMILY: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
          },
        },
        WORK: {
          subtypes: {
            MEETINGS: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
          },
        },
      },
      processing_config: {
        category_signals: {},
        settings: {
          disambiguation: {
            confidence_gap_threshold: 0.15, // 15% gap required for clear winner
            max_adjustments_per_email: 5,
            adjustment_decay_factor: 0.8,
            enable_subtype_disambiguation: true,
          },
        },
        confidence_thresholds: {
          high_confidence: 0.8,
          ai_classification_required: 0.4,
          low_confidence: 0.2,
        },
        multi_label_policy: {
          max_labels: 3,
          confidence_threshold: 0.3,
          allowed_combinations: [],
        },
        attribute_relevance: {
          _roles_legend: {
            CORE: 'Essential attributes that define the category',
            PRIMARY_BOOST: 'Strong positive indicators for the category',
            SECONDARY_BOOST: 'Moderate positive indicators',
            DISAMBIGUATOR: 'Helps choose between similar categories',
            FILTER: 'Rules out inappropriate categories',
            STRUCTURAL: 'Email structure and format indicators',
            DERIVED_LINK: 'Links to derived attribute calculations',
            NEUTRAL: 'No impact on category scoring',
          },
        },
        ai_prompts: {
          feature_extraction: {
            system_prompt: [],
            user_prompt: [],
          },
          final_classification: {
            system_prompt: [],
            user_prompt: [],
          },
        },
      },
    };
  });

  describe('Confidence Gap Analysis', () => {
    test('should detect competing categories within threshold', async () => {
      // Simulate email with previous stage data showing close scores
      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68, // Gap of 0.04 < 0.15 threshold
          WORK: 0.45,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.competing_categories).toContainEqual(
        expect.objectContaining({
          category1: 'FINANCIAL',
          category2: 'PERSONAL',
          score_gap: expect.closeTo(0.04, 2),
          requires_disambiguation: true,
        })
      );
    });

    test('should skip disambiguation for clear winners', async () => {
      // Clear winner scenario
      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.85,
          PERSONAL: 0.3, // Gap of 0.55 > 0.15 threshold
          WORK: 0.1, // Gap of 0.20 > 0.15 threshold
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.competing_categories).toHaveLength(0);
      expect(result.adjustments_applied).toHaveLength(0);
    });

    test('should handle multiple competing pairs', async () => {
      // Multiple close scores
      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.65,
          PERSONAL: 0.62, // Gap: 0.03
          WORK: 0.6, // Gap with PERSONAL: 0.02
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      // Should identify multiple competing pairs
      expect(result.competing_categories.length).toBeGreaterThanOrEqual(2);
    });
  });

  describe('Disambiguation Adjustments', () => {
    test('should apply DISAMBIGUATOR attribute bonuses', async () => {
      // Setup DISAMBIGUATOR attributes in context
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      // Configure DISAMBIGUATOR role
      mockConfig.processing_config.attribute_relevance.FINANCIAL = {
        category_roles: {
          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68, // Close scores needing disambiguation
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.adjustments_applied).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'urgent_indicator',
          role: 'DISAMBIGUATOR',
          adjustment_amount: expect.any(Number),
          adjustment_reason: 'disambiguator_bonus',
        })
      );
    });

    test('should apply score adjustments based on attribute confidence', async () => {
      // High confidence DISAMBIGUATOR attribute
      mockContext.detectionMetadata.priority_flag = {
        detectedAt: new Date(),
        detectionMethod: 'header_analysis',
        confidence: 0.95,
        evidence: 'High priority header found',
      };

      mockConfig.processing_config.attribute_relevance.WORK = {
        category_roles: {
          priority_flag: 'DISAMBIGUATOR',
        },
      };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.7,
          WORK: 0.68, // Close scores
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      const workAdjustment = result.adjustments_applied.find((adj) => adj.category === 'WORK');
      expect(workAdjustment?.adjustment_amount).toBeGreaterThan(0);
      expect(workAdjustment?.confidence_factor).toBe(0.95);
    });

    test('should enforce adjustment limits per email', async () => {
      // Setup multiple DISAMBIGUATOR attributes
      mockContext.detectionMetadata = {
        urgent_indicator: {
          detectedAt: new Date(),
          detectionMethod: 'keyword_analysis',
          confidence: 0.8,
          evidence: 'Urgent keywords',
        },
        priority_flag: {
          detectedAt: new Date(),
          detectionMethod: 'header_analysis',
          confidence: 0.9,
          evidence: 'Priority header',
        },
        deadline_mention: {
          detectedAt: new Date(),
          detectionMethod: 'text_analysis',
          confidence: 0.7,
          evidence: 'Deadline mentioned',
        },
        formal_language: {
          detectedAt: new Date(),
          detectionMethod: 'nlp_analysis',
          confidence: 0.6,
          evidence: 'Formal language detected',
        },
        business_hours: {
          detectedAt: new Date(),
          detectionMethod: 'temporal_analysis',
          confidence: 0.8,
          evidence: 'Sent during business hours',
        },
        personal_tone: {
          detectedAt: new Date(),
          detectionMethod: 'sentiment_analysis',
          confidence: 0.7,
          evidence: 'Personal tone detected',
        },
      };

      // Configure all as DISAMBIGUATOR attributes for different categories
      mockConfig.processing_config.attribute_relevance = {
        _roles_legend: mockConfig.processing_config.attribute_relevance._roles_legend,
        FINANCIAL: {
          category_roles: {
            urgent_indicator: 'DISAMBIGUATOR',
            deadline_mention: 'DISAMBIGUATOR',
          },
        },
        WORK: {
          category_roles: {
            priority_flag: 'DISAMBIGUATOR',
            formal_language: 'DISAMBIGUATOR',
            business_hours: 'DISAMBIGUATOR',
          },
        },
        PERSONAL: {
          category_roles: {
            personal_tone: 'DISAMBIGUATOR',
          },
        },
      };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.7,
          WORK: 0.68,
          PERSONAL: 0.66,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      // Should respect max_adjustments_per_email limit (5)
      expect(result.adjustments_applied.length).toBeLessThanOrEqual(5);
    });

    test('should apply decay factor to subsequent adjustments', async () => {
      // Setup multiple DISAMBIGUATOR attributes for same category
      mockContext.detectionMetadata = {
        urgent_indicator: {
          detectedAt: new Date(),
          detectionMethod: 'keyword_analysis',
          confidence: 0.8,
          evidence: 'Urgent keywords',
        },
        deadline_mention: {
          detectedAt: new Date(),
          detectionMethod: 'text_analysis',
          confidence: 0.8,
          evidence: 'Deadline mentioned',
        },
        priority_flag: {
          detectedAt: new Date(),
          detectionMethod: 'header_analysis',
          confidence: 0.8,
          evidence: 'Priority header',
        },
      };

      mockConfig.processing_config.attribute_relevance.FINANCIAL = {
        category_roles: {
          urgent_indicator: 'DISAMBIGUATOR',
          deadline_mention: 'DISAMBIGUATOR',
          priority_flag: 'DISAMBIGUATOR',
        },
      };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      const financialAdjustments = result.adjustments_applied.filter((adj) => adj.category === 'FINANCIAL');

      if (financialAdjustments.length >= 2) {
        // Second adjustment should be smaller due to decay factor (0.8)
        expect(financialAdjustments[1].adjustment_amount).toBeLessThan(financialAdjustments[0].adjustment_amount);
      }
    });
  });

  describe('Subtype Disambiguation', () => {
    test('should disambiguate between subtypes within same category', async () => {
      // Setup competing FINANCIAL subtypes
      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          'FINANCIAL.BILLING': 0.72,
          'FINANCIAL.INSURANCE': 0.68, // Close subtype scores
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.competing_categories).toContainEqual(
        expect.objectContaining({
          category1: 'FINANCIAL.BILLING',
          category2: 'FINANCIAL.INSURANCE',
          subtype_competition: true,
        })
      );
    });

    test('should respect subtype disambiguation configuration', async () => {
      // Disable subtype disambiguation
      mockConfig.processing_config.settings.disambiguation.enable_subtype_disambiguation = false;

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          'FINANCIAL.BILLING': 0.72,
          'FINANCIAL.INSURANCE': 0.68,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      // Should skip subtype disambiguation
      const subtypeCompetitions = result.competing_categories.filter((comp) => comp.subtype_competition);
      expect(subtypeCompetitions).toHaveLength(0);
    });
  });

  describe('Score Updates', () => {
    test('should update candidate scores after adjustments', async () => {
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      mockConfig.processing_config.attribute_relevance.FINANCIAL = {
        category_roles: {
          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      // Scores should be updated
      expect(result.updated_scores.FINANCIAL).toBeGreaterThan(0.72);
      expect(result.updated_scores.PERSONAL).toBe(0.68); // Unchanged
    });

    test('should preserve original scores in metadata', async () => {
      const originalScores = {
        FINANCIAL: 0.72,
        PERSONAL: 0.68,
      };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: originalScores,
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.original_scores).toEqual(originalScores);
    });

    test('should track score deltas', async () => {
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      mockConfig.processing_config.attribute_relevance.FINANCIAL = {
        category_roles: {
          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.score_deltas).toEqual(
        expect.objectContaining({
          FINANCIAL: expect.any(Number),
          PERSONAL: 0, // No change
        })
      );

      expect(result.score_deltas.FINANCIAL).toBeGreaterThan(0);
    });
  });

  describe('Performance and Processing Metadata', () => {
    test('should track processing duration', async () => {
      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.processing_duration_ms).toBeGreaterThan(0);
      expect(result.processing_duration_ms).toBeLessThan(1000); // Should be fast
    });

    test('should track configuration references', async () => {
      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      expect(result.configuration_references).toEqual(
        expect.objectContaining({
          disambiguation_settings_path: 'processing_config.settings.disambiguation',
          confidence_gap_threshold: 0.15,
        })
      );
    });

    test('should preserve existing context data', async () => {
      const originalContext = { ...mockContext };

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      const result = await executeDisambiguation(emailWithScores, mockContext, mockConfig);

      // Original context should be preserved
      expect(mockContext.emailId).toBe(originalContext.emailId);
      expect(mockContext.detectionMetadata).toEqual(originalContext.detectionMetadata);
    });
  });

  describe('Error Handling and Edge Cases', () => {
    test('should handle missing disambiguation configuration', async () => {
      // Remove disambiguation configuration
      delete mockConfig.processing_config.settings.disambiguation;

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      await expect(executeDisambiguation(emailWithScores, mockContext, mockConfig)).rejects.toThrow(
        'Disambiguation configuration not found'
      );
    });

    test('should handle missing candidate scores', async () => {
      const emailWithoutScores = { ...mockEmail };

      const result = await executeDisambiguation(emailWithoutScores, mockContext, mockConfig);

      expect(result.competing_categories).toHaveLength(0);
      expect(result.adjustments_applied).toHaveLength(0);
      expect(result.updated_scores).toEqual({});
    });

    test('should handle empty candidate scores', async () => {
      const emailWithEmptyScores = {
        ...mockEmail,
        candidate_scores: {},
      } as any;

      const result = await executeDisambiguation(emailWithEmptyScores, mockContext, mockConfig);

      expect(result.competing_categories).toHaveLength(0);
      expect(result.adjustments_applied).toHaveLength(0);
    });

    test('should handle single category score', async () => {
      const emailWithSingleScore = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.85,
        },
      } as any;

      const result = await executeDisambiguation(emailWithSingleScore, mockContext, mockConfig);

      // No disambiguation needed for single category
      expect(result.competing_categories).toHaveLength(0);
      expect(result.adjustments_applied).toHaveLength(0);
    });

    test('should validate confidence gap threshold', async () => {
      // Invalid threshold
      mockConfig.processing_config.settings.disambiguation.confidence_gap_threshold = -0.1;

      const emailWithScores = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
      } as any;

      await expect(executeDisambiguation(emailWithScores, mockContext, mockConfig)).rejects.toThrow(
        'Invalid confidence gap threshold'
      );
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should work with attribute influence results', async () => {
      // Simulate attribute influence stage results
      const emailWithInfluence = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
        stage_results: {
          attribute_influence: {
            completed: true,
            influence_applications: [
              {
                category: 'FINANCIAL',
                attribute: 'urgent_indicator',
                role: 'DISAMBIGUATOR',
                bonus_applied: 5,
              },
            ],
          },
        },
      } as any;

      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      const result = await executeDisambiguation(emailWithInfluence, mockContext, mockConfig);

      // Should use previous influence applications in disambiguation
      expect(result.adjustments_applied.length).toBeGreaterThan(0);
    });

    test('should preserve stage chain data', async () => {
      const emailWithStageData = {
        ...mockEmail,
        candidate_scores: {
          FINANCIAL: 0.72,
          PERSONAL: 0.68,
        },
        stage_results: {
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
          attribute_influence: { completed: true },
        },
      } as any;

      const result = await executeDisambiguation(emailWithStageData, mockContext, mockConfig);

      // Should preserve previous stage data
      expect(result.stage_results).toEqual(
        expect.objectContaining({
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
          attribute_influence: { completed: true },
          disambiguation: { completed: true },
        })
      );
    });
  });
});

