/**
 * Unit tests for T032: Attribute Influence Stage
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests validate:
 * - All role types (CORE, PRIMARY_BOOST, SECONDARY_BOOST, DISAMBIGUATOR, FILTER)
 * - Bonus calculations and score caps
 * - Role enforcement per SCORING_LOGIC.md
 * - Configuration validation
 */

import { describe, test, expect, beforeEach } from '@jest/globals';
import { EmailMessage } from '../../src/types/email-message';
import { AttributeContext } from '../../src/types/attribute-context';
import { CategoryConfiguration } from '../../src/types/category-configuration';
import { executeAttributeInfluence } from '../../src/stages/attribute-influence';

describe('Attribute Influence Stage (T032)', () => {
  let mockEmail: EmailMessage;
  let mockContext: AttributeContext;
  let mockConfig: CategoryConfiguration;

  beforeEach(() => {
    // Setup test email
    mockEmail = {
      id: 'test-email-123',
      threadId: 'thread-456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'test@example.com' },
          { name: 'Subject', value: 'Test Email' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' },
      },
      bodyPlain: 'Test email body',
      bodyHtml: '<p>Test email body</p>',
      subject: 'Test Email',
      from: 'test@example.com',
      to: ['recipient@example.com'],
      date: new Date('2024-01-01T10:00:00Z'),
      snippet: 'Test email body',
    } as EmailMessage;

    // Setup attribute context with detected attributes
    mockContext = {
      emailId: 'test-email-123',
      urgency: 'medium',
      domains: ['financial.com'],
      structuralPatterns: ['invoice_pattern'],
      temporalSignals: ['end_of_month'],
      detectionMetadata: {
        financial_domain: {
          detectedAt: new Date(),
          detectionMethod: 'domain_lookup',
          confidence: 0.95,
          evidence: 'financial.com domain',
        },
      },
      influenceApplications: [],
      derivedAttributes: {},
      attributeRelationships: [],
    };

    // Setup category configuration with attribute relevance matrix
    mockConfig = {
      version: '1.0',
      updated: '2024-01-01',
      top_level_categories: {
        FINANCIAL: {
          subtypes: {
            BILLING: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
          },
        },
        PERSONAL: {
          subtypes: {
            FAMILY: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
          },
        },
      },
      processing_config: {
        category_signals: {},
        settings: {
          disambiguation: {
            confidence_gap_threshold: 0.15,
          },
        },
        confidence_thresholds: {
          high_confidence: 0.8,
          ai_classification_required: 0.4,
          low_confidence: 0.2,
        },
        multi_label_policy: {
          max_labels: 3,
          confidence_threshold: 0.3,
          allowed_combinations: [],
        },
        // Attribute relevance matrix - key for this stage
        attribute_relevance: {
          _roles_legend: {
            CORE: 'Essential attributes that define the category',
            PRIMARY_BOOST: 'Strong positive indicators for the category',
            SECONDARY_BOOST: 'Moderate positive indicators',
            DISAMBIGUATOR: 'Helps choose between similar categories',
            FILTER: 'Rules out inappropriate categories',
            STRUCTURAL: 'Email structure and format indicators',
            DERIVED_LINK: 'Links to derived attribute calculations',
            NEUTRAL: 'No impact on category scoring',
          },
          FINANCIAL: {
            category_roles: {
              financial_domain: 'CORE',
              invoice_pattern: 'PRIMARY_BOOST',
              end_of_month: 'SECONDARY_BOOST',
              urgent_indicator: 'DISAMBIGUATOR',
            },
            subtypes: {
              BILLING: {
                roles: {
                  financial_domain: 'CORE',
                  invoice_pattern: 'CORE',
                  end_of_month: 'PRIMARY_BOOST',
                },
              },
            },
          },
          PERSONAL: {
            category_roles: {
              family_domain: 'CORE',
              personal_greeting: 'PRIMARY_BOOST',
              financial_domain: 'FILTER', // Filters out financial content
            },
            subtypes: {
              FAMILY: {
                roles: {
                  family_domain: 'CORE',
                  personal_greeting: 'CORE',
                },
              },
            },
          },
        },
        // Bonus configuration for different roles
        attribute_bonus_config: {
          role_bonuses: {
            CORE: { bonus: 25, cap: 50 },
            PRIMARY_BOOST: { bonus: 15, cap: 30 },
            SECONDARY_BOOST: { bonus: 8, cap: 16 },
            DISAMBIGUATOR: { bonus: 5, cap: 10 },
            FILTER: { bonus: -20, cap: -40 },
          },
        },
        ai_prompts: {
          feature_extraction: {
            system_prompt: [],
            user_prompt: [],
          },
          final_classification: {
            system_prompt: [],
            user_prompt: [],
          },
        },
      },
    };
  });

  describe('Core Role Processing', () => {
    test('should apply CORE role bonuses correctly', async () => {
      // This test MUST FAIL before implementation
      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // CORE attributes should get maximum bonus (25 points)
      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'financial_domain',
          role: 'CORE',
          bonus_applied: 25,
          score_before: expect.any(Number),
          score_after: expect.any(Number),
        })
      );
    });

    test('should enforce CORE role caps', async () => {
      // Multiple CORE attributes should be capped at 50 total
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.9,
        evidence: 'Invoice pattern detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const financialCoreInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'CORE'
      );

      // Group by subtype (category-level and BILLING subtype should be separate caps)
      const categoryLevelCores = financialCoreInfluences.filter((app) => !app.subtype);
      const billingSubtypeCores = financialCoreInfluences.filter((app) => app.subtype === 'BILLING');

      const categoryLevelTotal = categoryLevelCores.reduce((sum, app) => sum + app.bonus_applied, 0);
      const billingSubtypeTotal = billingSubtypeCores.reduce((sum, app) => sum + app.bonus_applied, 0);

      // Each group should be capped at 50
      expect(categoryLevelTotal).toBeLessThanOrEqual(50);
      expect(billingSubtypeTotal).toBeLessThanOrEqual(50);
    });
  });

  describe('PRIMARY_BOOST Role Processing', () => {
    test('should apply PRIMARY_BOOST bonuses correctly', async () => {
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.8,
        evidence: 'Invoice pattern detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'invoice_pattern',
          role: 'PRIMARY_BOOST',
          bonus_applied: 15,
          cap_reached: false,
        })
      );
    });

    test('should enforce PRIMARY_BOOST caps at 30 points', async () => {
      // Add multiple PRIMARY_BOOST attributes
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.8,
        evidence: 'Invoice pattern detected',
      };
      mockContext.detectionMetadata.billing_keyword = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_match',
        confidence: 0.7,
        evidence: 'Billing keyword found',
      };

      // Configure additional PRIMARY_BOOST attribute
      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.billing_keyword = 'PRIMARY_BOOST';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const primaryBoostInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'PRIMARY_BOOST'
      );

      const totalPrimaryBonus = primaryBoostInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalPrimaryBonus).toBeLessThanOrEqual(30);
    });
  });

  describe('SECONDARY_BOOST Role Processing', () => {
    test('should apply SECONDARY_BOOST bonuses correctly', async () => {
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.6,
        evidence: 'End of month timing',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'end_of_month',
          role: 'SECONDARY_BOOST',
          bonus_applied: 8,
        })
      );
    });

    test('should enforce SECONDARY_BOOST caps at 16 points', async () => {
      // Add multiple SECONDARY_BOOST attributes
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.6,
        evidence: 'End of month timing',
      };
      mockContext.detectionMetadata.business_hours = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.5,
        evidence: 'Business hours timing',
      };

      // Configure additional SECONDARY_BOOST attribute
      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.business_hours = 'SECONDARY_BOOST';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const secondaryBoostInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'SECONDARY_BOOST'
      );

      const totalSecondaryBonus = secondaryBoostInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalSecondaryBonus).toBeLessThanOrEqual(16);
    });
  });

  describe('DISAMBIGUATOR Role Processing', () => {
    test('should apply DISAMBIGUATOR bonuses for conflict resolution', async () => {
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.7,
        evidence: 'Urgent keywords found',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'urgent_indicator',
          role: 'DISAMBIGUATOR',
          bonus_applied: 5,
        })
      );
    });

    test('should enforce DISAMBIGUATOR caps at 10 points', async () => {
      // Add multiple DISAMBIGUATOR attributes
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.7,
        evidence: 'Urgent keywords found',
      };
      mockContext.detectionMetadata.priority_flag = {
        detectedAt: new Date(),
        detectionMethod: 'header_analysis',
        confidence: 0.6,
        evidence: 'Priority header found',
      };

      // Configure additional DISAMBIGUATOR attribute
      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.priority_flag = 'DISAMBIGUATOR';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const disambiguatorInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'DISAMBIGUATOR'
      );

      const totalDisambiguatorBonus = disambiguatorInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalDisambiguatorBonus).toBeLessThanOrEqual(10);
    });
  });

  describe('FILTER Role Processing', () => {
    test('should apply negative bonuses for FILTER attributes', async () => {
      // PERSONAL category has financial_domain as FILTER
      mockContext.detectionMetadata.financial_domain = {
        detectedAt: new Date(),
        detectionMethod: 'domain_lookup',
        confidence: 0.9,
        evidence: 'Financial domain detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should filter out PERSONAL category with negative bonus
      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'PERSONAL',
          attribute: 'financial_domain',
          role: 'FILTER',
          bonus_applied: -20, // Negative bonus
        })
      );
    });

    test('should enforce FILTER caps at -40 points', async () => {
      // Add multiple FILTER attributes for PERSONAL category
      mockContext.detectionMetadata.financial_domain = {
        detectedAt: new Date(),
        detectionMethod: 'domain_lookup',
        confidence: 0.9,
        evidence: 'Financial domain detected',
      };
      mockContext.detectionMetadata.business_language = {
        detectedAt: new Date(),
        detectionMethod: 'nlp_analysis',
        confidence: 0.8,
        evidence: 'Business language detected',
      };

      // Configure additional FILTER attribute
      mockConfig.processing_config.attribute_relevance.PERSONAL.category_roles.business_language = 'FILTER';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const filterInfluences = result.influence_applications.filter(
        (app) => app.category === 'PERSONAL' && app.role === 'FILTER'
      );

      const totalFilterPenalty = filterInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalFilterPenalty).toBeGreaterThanOrEqual(-40); // More negative than -40 not allowed
    });
  });

  describe('Subtype Role Processing', () => {
    test('should apply subtype-specific role bonuses', async () => {
      // BILLING subtype has invoice_pattern as CORE
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.9,
        evidence: 'Invoice pattern detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should apply subtype-specific bonus for FINANCIAL.BILLING
      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          subtype: 'BILLING',
          attribute: 'invoice_pattern',
          role: 'CORE',
          bonus_applied: 25,
        })
      );
    });

    test('should handle category vs subtype role conflicts', async () => {
      // end_of_month is SECONDARY_BOOST for category but PRIMARY_BOOST for BILLING subtype
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.7,
        evidence: 'End of month timing',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Subtype role should take precedence
      const subtypeInfluence = result.influence_applications.find(
        (app) => app.category === 'FINANCIAL' && app.subtype === 'BILLING' && app.attribute === 'end_of_month'
      );

      expect(subtypeInfluence).toEqual(
        expect.objectContaining({
          role: 'PRIMARY_BOOST', // Subtype role takes precedence
          bonus_applied: 15, // PRIMARY_BOOST bonus
        })
      );
    });
  });

  describe('Performance and Processing Metadata', () => {
    test('should track processing duration', async () => {
      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.processing_duration_ms).toBeGreaterThan(0);
      expect(result.processing_duration_ms).toBeLessThan(1000); // Should be fast
    });

    test('should track configuration references', async () => {
      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.configuration_references).toEqual(
        expect.objectContaining({
          attribute_relevance_path: 'processing_config.attribute_relevance',
          bonus_config_path: 'processing_config.attribute_bonus_config',
        })
      );
    });

    test('should preserve existing context data', async () => {
      const originalContext = { ...mockContext };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Original context should be preserved
      expect(mockContext.emailId).toBe(originalContext.emailId);
      expect(mockContext.detectionMetadata).toEqual(originalContext.detectionMetadata);
    });
  });

  describe('Error Handling and Edge Cases', () => {
    test('should handle missing attribute relevance configuration', async () => {
      // Remove attribute relevance configuration
      delete mockConfig.processing_config.attribute_relevance;

      await expect(executeAttributeInfluence(mockEmail, mockContext, mockConfig)).rejects.toThrow(
        'Attribute relevance configuration not found'
      );
    });

    test('should handle unknown attributes gracefully', async () => {
      // Add unknown attribute to context
      mockContext.detectionMetadata.unknown_attribute = {
        detectedAt: new Date(),
        detectionMethod: 'unknown',
        confidence: 0.5,
        evidence: 'Unknown attribute',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should not crash, unknown attributes ignored
      expect(result.influence_applications).not.toContainEqual(
        expect.objectContaining({
          attribute: 'unknown_attribute',
        })
      );
    });

    test('should handle empty detection metadata', async () => {
      mockContext.detectionMetadata = {};

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toHaveLength(0);
      expect(result.processing_duration_ms).toBeGreaterThan(0);
    });

    test('should validate role configurations', async () => {
      // Invalid role in configuration
      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.financial_domain =
        'INVALID_ROLE' as any;

      await expect(executeAttributeInfluence(mockEmail, mockContext, mockConfig)).rejects.toThrow(
        'Invalid attribute role: INVALID_ROLE'
      );
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should work with attribute detection results', async () => {
      // Simulate typical attribute detection output
      mockContext.detectionMetadata = {
        financial_domain: {
          detectedAt: new Date(),
          detectionMethod: 'domain_lookup',
          confidence: 0.95,
          evidence: 'Domain: financial.com',
        },
        invoice_pattern: {
          detectedAt: new Date(),
          detectionMethod: 'regex_pattern',
          confidence: 0.88,
          evidence: 'Invoice number pattern found',
        },
        end_of_month: {
          detectedAt: new Date(),
          detectionMethod: 'temporal_analysis',
          confidence: 0.72,
          evidence: 'Email sent on last day of month',
        },
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should process all detected attributes with appropriate roles
      // 3 attributes but some attributes apply to both category and subtype levels
      expect(result.influence_applications.length).toBeGreaterThan(0);

      const financialInfluences = result.influence_applications.filter((app) => app.category === 'FINANCIAL');
      expect(financialInfluences.length).toBeGreaterThan(0); // Should have financial influences
    });

    test('should preserve stage chain data', async () => {
      // Simulate data from previous stages
      const emailWithStageData = {
        ...mockEmail,
        stage_results: {
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
        },
      } as any;

      const result = await executeAttributeInfluence(emailWithStageData, mockContext, mockConfig);

      // Should preserve previous stage data
      expect(result.stage_results).toEqual(
        expect.objectContaining({
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
          attribute_influence: { completed: true },
        })
      );
    });
  });
});

