  describe('Core Role Processing', () => {
    test('should apply CORE role bonuses correctly', async () => {
      // This test MUST FAIL before implementation
      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // CORE attributes should get maximum bonus (25 points)
      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'financial_domain',
          role: 'CORE',
          bonus_applied: 25,
          score_before: expect.any(Number),
          score_after: expect.any(Number),
        })
      );
    });

    test('should enforce CORE role caps', async () => {
      // Multiple CORE attributes should be capped at 50 total
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.9,
        evidence: 'Invoice pattern detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const financialCoreInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'CORE'
      );

      // Group by subtype (category-level and BILLING subtype should be separate caps)
      const categoryLevelCores = financialCoreInfluences.filter((app) => !app.subtype);
      const billingSubtypeCores = financialCoreInfluences.filter((app) => app.subtype === 'BILLING');

      const categoryLevelTotal = categoryLevelCores.reduce((sum, app) => sum + app.bonus_applied, 0);
      const billingSubtypeTotal = billingSubtypeCores.reduce((sum, app) => sum + app.bonus_applied, 0);

      // Each group should be capped at 50
      expect(categoryLevelTotal).toBeLessThanOrEqual(50);
      expect(billingSubtypeTotal).toBeLessThanOrEqual(50);
    });
  });

  describe('PRIMARY_BOOST Role Processing', () => {
    test('should apply PRIMARY_BOOST bonuses correctly', async () => {
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.8,
        evidence: 'Invoice pattern detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'invoice_pattern',
          role: 'PRIMARY_BOOST',
          bonus_applied: 15,
          cap_reached: false,
        })
      );
    });

    test('should enforce PRIMARY_BOOST caps at 30 points', async () => {
      // Add multiple PRIMARY_BOOST attributes
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.8,
        evidence: 'Invoice pattern detected',
      };
      mockContext.detectionMetadata.billing_keyword = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_match',
        confidence: 0.7,
        evidence: 'Billing keyword found',
      };

      // Configure additional PRIMARY_BOOST attribute
      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.billing_keyword = 'PRIMARY_BOOST';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const primaryBoostInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'PRIMARY_BOOST'
      );

      const totalPrimaryBonus = primaryBoostInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalPrimaryBonus).toBeLessThanOrEqual(30);
    });
  });

  describe('SECONDARY_BOOST Role Processing', () => {
    test('should apply SECONDARY_BOOST bonuses correctly', async () => {
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.6,
        evidence: 'End of month timing',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'end_of_month',
          role: 'SECONDARY_BOOST',
          bonus_applied: 8,
        })
      );
    });

    test('should enforce SECONDARY_BOOST caps at 16 points', async () => {
      // Add multiple SECONDARY_BOOST attributes
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.6,
        evidence: 'End of month timing',
      };
      mockContext.detectionMetadata.business_hours = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.5,
        evidence: 'Business hours timing',
      };

      // Configure additional SECONDARY_BOOST attribute
      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.business_hours = 'SECONDARY_BOOST';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const secondaryBoostInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'SECONDARY_BOOST'
      );

      const totalSecondaryBonus = secondaryBoostInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalSecondaryBonus).toBeLessThanOrEqual(16);
    });
