      // end_of_month is SECONDARY_BOOST for category but PRIMARY_BOOST for BILLING subtype
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'temporal_analysis',
        confidence: 0.7,
        evidence: 'End of month timing',
